    },
    {
      "name": "causesIllnessOrIncapacity",
      "args": [
        "Person"
      ],
      "returns": "Bool"
    },
    {
      "name": "intentionallyInflictsWoundsOrBlows",
      "args": [
        "Person"
      ],
      "returns": "Bool"
    },
    {
      "name": "punishedArt398",
      "args": [
        "Person"
      ],
      "returns": "Bool"
    },
    {
      "name": "punishedArt399",
      "args": [
        "Person"
